  const channelId = $('Parse Agent Response').first().json.channel_id;
  const threadTs = $('Parse Agent Response').first().json.thread_ts;

  const blocks = [
    { type: 'section', text: { type: 'mrkdwn', text: ':moneybag: *経理AI回答*' } },
    { type: 'section', text: { type: 'mrkdwn', text: aiText } },
    { type: 'divider' },
    { type: 'context', elements: [{ type: 'mrkdwn', text: ':ticket: チケット: `' + ticketId + '` | :label: ' + category + ' | :zap: ' + priority }] },
    { type: 'section', text: { type: 'mrkdwn', text: 'この回答は役に立ちましたか？' } }
  ];

  const actionElements = [
    { type: 'button', text: { type: 'plain_text', text: '✅ 解決しました' }, style: 'primary', action_id: 'resolved', value: JSON.stringify({ log_id: logId, ticket_id: ticketId, category: 'finance' }) },
    { type: 'button', text: { type: 'plain_text', text: '📝 有人対応依頼' }, action_id: 'direct_ticket', value: JSON.stringify({ log_id: logId, ticket_id: ticketId, category: 'finance' }) },
    { type: 'button', text: { type: 'plain_text', text: '🚨 緊急エスカレーション' }, style: 'danger', action_id: 'escalate', value: JSON.stringify({ log_id: logId, ticket_id: ticketId, category: 'finance' }) }
  ];
  blocks.push({ type: 'actions', block_id: 'finance_feedback_' + logId, elements: actionElements });

  return JSON.stringify({ channel: channelId, thread_ts: threadTs, text: 'AI回答', blocks: blocks });
})() }}
